#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,B=1;

struct Edge{
    int u,v,w;
    bool operator<(Edge x)const{
        return w<x.w;
    }
};

struct Node{
	int sz,val,cnt,res,fa,ch[2];
}a[N];

int n,q,f[N],tot,root,top;
set<Edge> edge;
queue<int> rq;
Edge stk[N],add[N*5];
bool b[N*5];

int New(int val){
	int x=rq.front();
	rq.pop();
	a[x].sz=a[x].cnt=1;
	a[x].val=a[x].res=val;
	a[x].fa=a[x].ch[0]=a[x].ch[1]=0;
	return x;
}

int dir(int p){
	return a[a[p].fa].ch[1]==p;
}

void Pushup(int p){
	a[p].sz=a[a[p].ch[0]].sz+a[p].cnt+a[a[p].ch[1]].sz;
	a[p].res=a[a[p].ch[0]].res;
	if(a[a[p].ch[0]].sz%2)
		a[p].res-=a[p].cnt%2*a[p].val;
	else
		a[p].res+=a[p].cnt%2*a[p].val;
	if((a[p].sz-a[a[p].ch[1]].sz)%2)
		a[p].res-=a[a[p].ch[1]].res;
	else
		a[p].res+=a[a[p].ch[1]].res; 
}

void Rotate(int p){
	int x=a[p].fa,y=a[x].fa,r=dir(p);
	if(y) a[y].ch[dir(x)]=p;
	a[p].fa=y;
	a[x].ch[r]=a[p].ch[!r],a[a[x].ch[r]].fa=x;
	a[p].ch[!r]=x,a[x].fa=p;
	Pushup(x),Pushup(p);
}

void Splay(int p){
	root=p;
	for(;a[p].fa;)
		if(a[a[p].fa].fa && dir(p)==dir(a[p].fa))
			Rotate(a[p].fa),Rotate(p);
		else{
			Rotate(p);
			if(a[p].fa) Rotate(p);
		}
	Pushup(p);
}

void Insert(int val){
//	printf("Insert %d %d\n",val,root);
	int p=root,lst=0;
	while(p){
		lst=p;
		if(a[p].val==val){
			a[p].cnt++;
			break;
		}
		p=a[p].ch[a[p].val<val];
	}
	if(!p){
		p=New(val);
		a[p].fa=lst;
		if(lst)
			a[lst].ch[a[lst].val<val]=p;
		for(;lst;lst=a[lst].fa)
			Pushup(lst);
	}
//	printf("Splay %d\n",p);
	Splay(p);
//	printf("af %d %d %d\n",a[p].sz,a[p].res,a[p].val);
}

void Bind(int x,int y){
	if(!x || !y){
		root=max(x,y);
		return;
	}
	while(a[x].ch[1])
		x=a[x].ch[1];
	Splay(x);
	a[x].ch[1]=y;
	Pushup(x);
}

void Remove(int val){
	int p=root;
	while(p && a[p].val!=val)
		p=a[p].ch[a[p].val<val];
	if(!p)
		return;
	Splay(p);
	a[p].cnt--;
	Pushup(p);
	if(!a[p].cnt){
		rq.push(p);
		a[a[p].ch[0]].fa=a[a[p].ch[1]].fa=0;
		Bind(a[p].ch[0],a[p].ch[1]);
	}
}

int father(int x){ 
	return f[x]<0?x:father(f[x]);
}

bool Merge(Edge x){
	int fu=father(x.u),fv=father(x.v);
	if(fu!=fv){
		if(f[fu]>f[fv])
			swap(fu,fv);
//		printf("Merge %d %d %d %d\n",fu,-f[fu],fv,-f[fv]);
		Remove(-f[fu]),Remove(-f[fv]);
		stk[++top]={fu,fv,f[fv]};
		f[fu]+=f[fv],f[fv]=fu;
		Insert(-f[fu]);
		return true;
	}
	return false;
}

void Rev(){
	int x=stk[top].u,y=stk[top].v;
	Remove(-f[x]);
	f[y]=stk[top].w;
	f[x]-=f[y];
	Insert(-f[x]),Insert(-f[y]); 
	top--;
}

void output(int p){
	if(!p)
		return;
	printf("%d,%d ",a[p].val,a[p].cnt);
	printf("[");
	output(a[p].ch[0]);
	printf("][");
	output(a[p].ch[1]);
	printf("]");
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++){
		rq.push(i);
        f[i]=-1,Insert(1);
    }
//    output(root);
//    puts("");
    while(q--){
        char op[2];
        int u,v,p;
        scanf("%s",op);
        if(op[0]=='a'){
            scanf("%d%d%d",&u,&v,&p);
            edge.insert({u,v,p});
        }else if(op[0]=='r'){
            if(tot || edge.size()){
                if(edge.size()==0){
                    if(b[tot])
						Rev();
                    tot--;
                }else{
                    auto it=edge.end();
                    it--;
                    if(!tot || add[tot]<(*it))
                        edge.erase(it);
                    else{
                        if(b[tot])
    						Rev();
                        tot--;
                    }
                }
            }
        }else{
    		int lst=top;
//            printf("root %d\n",root);
            for(auto i:edge){
                Merge(i);
//                printf("add (%d, %d, %d)\n",i.u,i.v,i.w);
//                output(root);
//                puts("");
            }
//            for(int i=1;i<=n;i++)
//            	printf("%d ",f[i]);
//            puts("");
//            printf("root %d\n",root);
//            output(root);
//            puts("");
//			printf("%d %d %d\n",a[root].cnt,a[root].val,a[root].sz);
            printf("%d\n",abs(a[root].res));
            fflush(stdout);
            while(top>lst)
            	Rev();
        }
        if(edge.size()==B){
        	root=0;
        	top=0;
        	while(rq.size()) rq.pop();
        	for(int i=1;i<=n;i++){
        		rq.push(i),f[i]=-1;
        		Insert(1);
			}
        	for(auto i:edge)
        		add[++tot]=i;
        	edge.clear();
        	sort(add+1,add+tot+1);
        	for(int i=1;i<=tot;i++)
				b[i]=Merge(add[i]);
		}
    }
    return 0;
}
